class TaskPublisher(RabbitMQBase):
    def publish_task(self, task: str) -> str:
        if not self.channel or self.channel.is_closed:
            self.connect()

        task_id = str(uuid.uuid4())
        payload = {
            "task_id": task_id,
            "task": task,
            "created_at": int(time.time()),
        }

        self.channel.basic_publish(
            exchange="",
            routing_key=self.config.queue_name,
            body=json.dumps(payload),
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type="application/json",
            ),
        )
        return task_id


class TaskConsumer(RabbitMQBase):
    def __init__(self, config: RabbitMQConfig, processing_time: float = 1.0):
        super().__init__(config)
        self.processing_time = processing_time
        self._stopping = False

    def process_task(self, body: bytes) -> None:
        message = json.loads(body.decode("utf-8"))
        task_id = message.get("task_id", "unknown")
        task = message.get("task", "")
        print(f"[x] Processing task_id={task_id} task={task}")
        time.sleep(self.processing_time)
        print(f"[✓] Completed task_id={task_id}")

    def _callback(self, ch, method, properties, body) -> None:
        try:
            self.process_task(body)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as exc:
            print(f"[!] Error processing message: {exc}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    def start_consuming(self) -> None:
        if not self.channel or self.channel.is_closed:
            self.connect()

        self.channel.basic_qos(prefetch_count=1)
        self.channel.basic_consume(queue=self.config.queue_name, on_message_callback=self._callback)
        print("[*] Waiting for tasks. Press CTRL+C to exit.")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            self.stop()

    def stop(self) -> None:
        self._stopping = True
        try:
            if self.channel and self.channel.is_open and self.channel.is_consuming:
                self.channel.stop_consuming()
        finally:
            self.close()


